[workspace]

exclude = ["arceos", "crates/axconfig-gen", "crates/ext4plus"]
members = ["pulse_core", "pulse_syscalls"]

[workspace.package]
version = "0.1.0"
edition = "2024"
authors = ["muou000 <muou000@outlook.com>"]
license = "Apache-2.0"
homepage = "https://github.com/muou000/PulseOS"
repository = "https://github.com/muou000/PulseOS"

[workspace.dependencies]
axfeat = { path = "arceos/api/axfeat", features = [
    "alloc-tlsf",
    "page-alloc-4g",
    "multitask",
    "sched-rr",
    "fs",
    "rtc",
    "paging",
    "irq",
    "net",
] }

axconfig = { path = "arceos/modules/axconfig" }
axhal = { path = "arceos/modules/axhal", features = ["uspace", "fp-simd"] }
axlog = { path = "arceos/modules/axlog" }
axruntime = { path = "arceos/modules/axruntime" }
axnet = { path = "arceos/modules/axnet", features = ["monolithic"] }
axalloc = { path = "arceos/modules/axalloc" }
axtask = { path = "arceos/modules/axtask" }
axfs = { path = "arceos/modules/axfs", features = ["times"] }
axmm = { path = "arceos/modules/axmm" }
axerrno = "0.2"
axpoll = "0.3"

axplat-riscv64-qemu-virt = "0.3.0"
axplat-loongarch64-qemu-virt = "0.3.0"

syscalls = { version = "0.8", default-features = false }
linux-raw-sys = { version = "0.12", default-features = false, features = [
    "no_std",
    "general",
    "net",
    "ioctl",
    "loop_device",
] }
axio = { version = "0.3.0-pre.1", default-features = false, features = [
    "alloc",
] }
axfs-ng-vfs = "0.1.1"
linkme = "0.3"
memory_addr = "0.4"
bitflags = "2.11"
spin = "0.10"
kernel-elf-parser = "0.3"
xmas-elf = "0.9"
percpu = "0.2"
kernel_guard = "0.1"
rand = { version = "0.9.2", default-features = false }
rand_core = { version = "0.10.1", default-features = false }
rand_pcg = { version = "0.10.2", default-features = false }
chrono = { version = "0.4", default-features = false }

starry-vdso = { path = "crates/starry-vdso" }

[patch.crates-io]
axsched = { path = "crates/axsched" }
memory_set = { path = "crates/memory_set" }
memory_addr = { path = "crates/memory_addr" }
axfs-ng-vfs = { path = "crates/axfs-ng-vfs" }
axcpu = { path = "crates/axcpu" }
axplat-loongarch64-qemu-virt = { path = "crates/axplat-loongarch64-qemu-virt" }
axplat-riscv64-qemu-virt = { path = "crates/axplat-riscv64-qemu-virt" }
axio = { path = "crates/axio" }
virtio-drivers = { path = "crates/virtio-drivers" }
page_table_multiarch = { path = "crates/page_table_multiarch" }

[patch."https://github.com/arceos-org/allocator.git"]
allocator = { path = "crates/allocator" }

[package]
name = "Pulse"
version.workspace = true
edition.workspace = true
authors.workspace = true
license.workspace = true
homepage.workspace = true
repository.workspace = true

[features]
default = []
qemu = []
testcode = []

[dependencies]
axhal.workspace = true
axlog.workspace = true
axruntime.workspace = true
axfeat.workspace = true
axtask.workspace = true
pulse_syscalls = { path = "pulse_syscalls" }
pulse_core = { path = "pulse_core" }
starry-vdso.workspace = true

[target.'cfg(target_arch = "riscv64")'.dependencies]
axplat-riscv64-qemu-virt.workspace = true

[target.'cfg(target_arch = "loongarch64")'.dependencies]
axplat-loongarch64-qemu-virt.workspace = true

[patch."https://github.com/rcore-os/smoltcp.git"]
smoltcp = { path = "crates/smoltcp" }

export A := $(PWD)
export NAME := $(notdir $(A))
export PATH := $(A)/bin:$(PATH)
export NO_AXSTD := y
export AX_LIB := axfeat
export APP_FEATURES := qemu
export BLK := y

export MEM := 1G
export ARCH ?= riscv64
export LOG ?= info

QPERF ?= n
ifeq ($(QPERF),y)
  EXTRA_RUSTFLAGS := -C debuginfo=2 -C force-frame-pointers=yes -C strip=none
endif

IMG ?= n

prepare-tools:
	@if [ -d cargo ] && [ ! -d .cargo ]; then mv cargo .cargo; fi
	@command -v axconfig-gen >/dev/null || (echo "Error: missing axconfig-gen in PATH (expected in $(A)/bin)"; exit 1)
	@command -v cargo-axplat >/dev/null || (echo "Error: missing cargo-axplat in PATH (expected in $(A)/bin)"; exit 1)
	@command -v rust-objcopy >/dev/null || (echo "Error: missing rust-objcopy in PATH (expected in $(A)/bin)"; exit 1)
	@command -v rust-objdump >/dev/null || (echo "Error: missing rust-objdump in PATH (expected in $(A)/bin)"; exit 1)
	@echo "[tools] Using prebuilt tools from $(A)/bin"

all: prepare-tools
	@ARCH=riscv64 APP_FEATURES=qemu,testcode LOG=off $(MAKE) defconfig
	@ARCH=riscv64 APP_FEATURES=qemu,testcode LOG=off BUS=mmio $(MAKE) -C arceos build
	@cp $(NAME)_riscv64-qemu-virt.bin kernel-rv
	@ARCH=loongarch64 APP_FEATURES=qemu,testcode LOG=off FEATURES=bus-pci $(MAKE) defconfig
	@ARCH=loongarch64 APP_FEATURES=qemu,testcode LOG=off BUS=pci FEATURES=bus-pci $(MAKE) -C arceos build
	@cp $(NAME)_loongarch64-qemu-virt.elf kernel-la
	@$(MAKE) img_all

test: prepare-tools
	@ARCH=riscv64 APP_FEATURES=qemu,testcode LOG=$(LOG) $(MAKE) defconfig
	@ARCH=riscv64 APP_FEATURES=qemu,testcode LOG=$(LOG) BUS=mmio $(MAKE) -C arceos build  EXTRA_RUSTFLAGS="$(EXTRA_RUSTFLAGS)"
	@cp $(NAME)_riscv64-qemu-virt.bin kernel-rv
	@ARCH=loongarch64 APP_FEATURES=qemu,testcode LOG=$(LOG) FEATURES=bus-pci $(MAKE) defconfig
	@ARCH=loongarch64 APP_FEATURES=qemu,testcode LOG=$(LOG) BUS=pci FEATURES=bus-pci $(MAKE) -C arceos build  EXTRA_RUSTFLAGS="$(EXTRA_RUSTFLAGS)"
	@cp $(NAME)_loongarch64-qemu-virt.elf kernel-la
	@if [ "$(IMG)" = "y" ]; then $(MAKE) img_all; fi

debug: prepare-tools
	@ARCH=riscv64 APP_FEATURES=qemu LOG=$(LOG) $(MAKE) defconfig
	@ARCH=riscv64 APP_FEATURES=qemu LOG=$(LOG) BUS=mmio $(MAKE) -C arceos build
	@cp $(NAME)_riscv64-qemu-virt.bin kernel-rv
	@ARCH=loongarch64 APP_FEATURES=qemu LOG=$(LOG) FEATURES=bus-pci $(MAKE) defconfig
	@ARCH=loongarch64 APP_FEATURES=qemu LOG=$(LOG) BUS=pci FEATURES=bus-pci $(MAKE) -C arceos build
	@cp $(NAME)_loongarch64-qemu-virt.elf kernel-la

build run justrun: prepare-tools defconfig
	@$(MAKE) -C arceos A=$(A) ARCH=$(ARCH) $@

clean:
	@$(MAKE) -C arceos A=$(A) $@
	@rm -f .axconfig.toml
	@rm -f kernel-rv kernel-la
	@rm -f PulseOS_riscv64-qemu-virt.elf PulseOS_riscv64-qemu-virt.bin
	@rm -f PulseOS_loongarch64-qemu-virt.elf PulseOS_loongarch64-qemu-virt.bin
	@rm -f disk.img disk-la.img
	@rm -f rootfs-riscv64.img rootfs-loongarch64.img
	@rm -f arceos/disk.img arceos/disk-la.img

defconfig: prepare-tools
	@rm -f .axconfig.toml
	@$(MAKE) -C arceos A=$(A) ARCH=$(ARCH) $@

img_all:
	@./build_img.sh all
	@cp rootfs-riscv64.img disk.img
	@cp rootfs-loongarch64.img disk-la.img
	@cp disk.img arceos/disk.img
	@cp disk-la.img arceos/disk-la.img

la: prepare-tools
	@$(MAKE) ARCH=loongarch64 defconfig
	@$(MAKE) -C arceos A=$(A) ARCH=loongarch64 run

analyze: prepare-tools
	@$(MAKE) QPERF=y LOG=$(LOG) test

.PHONY: all test debug build run justrun clean defconfig img_all la analyze prepare-tools

#![no_std]
#![no_main]

#[macro_use]
extern crate axlog;
extern crate alloc;
extern crate axhal;
extern crate axruntime;
extern crate pulse_core;
extern crate pulse_syscalls;
extern crate starry_vdso;

#[unsafe(no_mangle)]
fn main() {
    starry_vdso::vdso::init_vdso_data();
    axruntime::vdso::set_update_hook(starry_vdso::vdso::update_vdso_data);

    pulse_core::task::init_itimer_hook();
    info!("itimer hook registered");

    if cfg!(feature = "testcode") {
        pulse_core::task::set_stdin_polling_enabled(false);
        info!("testcode feature active: stdin polling disabled");
    }

    pulse_core::task::init_procfs_provider();
    info!("procfs provider registered");

    pulse_core::fd_table::init_tty_callbacks();
    info!("TTY callbacks registered");

    pulse_core::trap::init();

    use axtask::TaskInner;
    const SHELL_ELF_PATH: &str = "/bin/sh";
    let mut inner = TaskInner::new(
        || {
            let thread =
                pulse_core::task::current_thread().expect("init task entered without Thread");
            let proc = thread.process();
            proc.activate();
            info!("User process address space activated");

            let shell_args: &[&str] = if cfg!(feature = "testcode") {
                &["sh", "/testcode.sh"]
            } else {
                &["sh"]
            };

            let shell_envs: &[&str] = &["PATH=/usr/sbin:/usr/bin:/sbin:/bin"];
            match proc.load_elf(SHELL_ELF_PATH, shell_args, shell_envs) {
                Ok(_) => {
                    info!("Successfully loaded {}", SHELL_ELF_PATH);
                    proc.enter_user_mode();
                }
                Err(e) => {
                    error!("Failed to load {}: {:?}", SHELL_ELF_PATH, e);
                    thread.exit_current(1);
                }
            }
        },
        "pulse_init".into(),
        0x8000,
    );
    let init_tid = inner.id().as_u64();
    match pulse_core::task::Process::new_uspace(init_tid) {
        Ok(proc) => {
            let init_thread = pulse_core::task::Thread::new(proc.clone());
            pulse_core::task::register_thread_global(init_tid, init_thread.clone());
            info!("Created initial user process");

            let pt_root = init_thread.process().page_table_root();
            let asid = init_thread.process().asid();
            inner.ctx_mut().set_page_table_root(pt_root, asid);

            init_thread.process().sync_fs_context();

            let init_proc = init_thread.process_arc();
            pulse_core::task::register_process(init_proc.pid(), init_proc.clone());
            inner.init_task_ext(pulse_core::task::ThreadHandle::new(init_thread.clone()));
            let init_task = axtask::spawn_task(inner);
            init_thread.process().register_task_ref(init_task.clone());

            match init_task.join() {
                Some(0) => info!("Init task exited normally"),
                Some(exit_code) => error!("Init task exited with failure code {}", exit_code),
                None => error!("Init task join returned no exit code"),
            }
            pulse_core::task::unregister_thread_global(init_tid);
            let _ = init_thread.process().take_task_ref_by_tid(init_tid);
            init_thread.process().release_task_refs();

            pulse_syscalls::sys_sync();
            axhal::power::system_off();
        }
        Err(e) => {
            error!("Failed to create user process: {:?}", e);
            pulse_syscalls::sys_sync();
            axhal::power::system_off();
        }
    }
}

