fn syscall_dispatcher(
    tf: &mut TrapFrame,
    syscall_id: usize,
    args: [usize; 6],
    process: &pulse_core::task::Process,
) -> isize {
    let sysno = match Sysno::new(syscall_id) {
        Some(sysno) => sysno,
        None => {
            axlog::warn!("Unknown syscall: {}", syscall_id);
            return -LinuxError::ENOSYS.code() as isize;
        }
    };

    let mut is_fs_syscall = matches!(
        sysno,
        Sysno::openat
            | Sysno::mkdirat
            | Sysno::mknodat
            | Sysno::mount
            | Sysno::umount2
            | Sysno::chroot
            | Sysno::statfs
            | Sysno::statx
            | Sysno::getcwd
            | Sysno::chdir
            | Sysno::fchdir
            | Sysno::unlinkat
            | Sysno::linkat
            | Sysno::renameat2
            | Sysno::utimensat
            | Sysno::readlinkat
            | Sysno::symlinkat
            | Sysno::faccessat
            | Sysno::faccessat2
            | Sysno::fchmodat
            | Sysno::fchownat
            | Sysno::execve
            | Sysno::execveat
            | Sysno::getrandom
    );
    #[cfg(target_arch = "loongarch64")]
    {
        is_fs_syscall |= matches!(sysno, Sysno::fstatat | Sysno::renameat);
    }
    #[cfg(target_arch = "riscv64")]
