        let actions = *from.handlers.actions.lock();
        Arc::new(Self {
            handlers: Arc::new(SignalHandlers {
                actions: SpinNoIrq::new(actions),
            }),
            process_pending: AtomicU64::new(0),
            pending_siginfo: Mutex::new(BTreeMap::new()),
        })
    }

