        let mut actions = self.handlers.actions.lock();
        for sig in 1..=NSIG {
            let h = actions[sig].handler;
            if h != SIG_IGN {
                actions[sig] = SigAction::dfl();
            }
        }
        self.process_pending.store(0, Ordering::Release);
        self.pending_siginfo.lock().clear();
    }

