//! System V semaphore implementation.

extern crate alloc;

use alloc::{collections::BTreeMap, sync::Arc, vec::Vec};
use core::sync::atomic::{AtomicI32, Ordering};
use spin::{Lazy, Mutex};
use axerrno::{AxError, AxResult, ax_err};
