// IPC constants
pub const IPC_PRIVATE: i32 = 0;
pub const IPC_CREAT: i32 = 0o1000;
pub const IPC_EXCL: i32 = 0o2000;
pub const IPC_RMID: i32 = 0;
pub const IPC_SET: i32 = 1;
pub const IPC_STAT: i32 = 2;
pub const IPC_INFO: i32 = 3;
pub const GETPID: i32 = 11;
pub const GETVAL: i32 = 12;
pub const GETALL: i32 = 13;
pub const GETNCNT: i32 = 14;
pub const GETZCNT: i32 = 15;
pub const SETVAL: i32 = 16;
pub const SETALL: i32 = 17;

/// Linux-compatible `ipc_perm` structure (C ABI).
#[repr(C)]
#[derive(Clone, Copy, Default)]
pub struct IpcPerm {
    pub key: i32,
    pub uid: u32,
    pub gid: u32,
    pub cuid: u32,
    pub cgid: u32,
    pub mode: u16,
    _pad: [u8; 2],
    _seq: u16,
    _pad2: u16,
    _pad3: u32,
    _pad4: u32,
}

impl IpcPerm {
    pub fn new(key: i32, mode: u16, pid: i32) -> Self {
        Self {
            key,
            uid: 0,
            gid: 0,
            cuid: pid as u32,
            cgid: pid as u32,
            mode,
            _pad: [0; 2],
            _seq: 0,
            _pad2: 0,
            _pad3: 0,
            _pad4: 0,
        }
    }
}

/// Linux-compatible `semid_ds` structure (C ABI).
#[repr(C)]
#[derive(Clone, Copy, Default)]
pub struct SemidDs {
    pub sem_perm: IpcPerm,
    pub sem_otime: i64,
    pub sem_ctime: i64,
    pub sem_nsems: usize,
    _reserved3: usize,
    _reserved4: usize,
}

impl SemidDs {
    pub fn new(key: i32, nsems: usize, mode: u16, pid: i32) -> Self {
        let now = axhal::time::wall_time().as_secs() as i64;
        Self {
            sem_perm: IpcPerm::new(key, mode, pid),
            sem_otime: 0,
            sem_ctime: now,
