            _reserved3: 0,
            _reserved4: 0,
        }
    }
}

pub struct Sem {
    pub semval: u16,
    pub sempid: i32,
    pub semncnt: u16,
    pub semzcnt: u16,
}

pub struct SemSetInner {
    pub semid: i32,
    pub nsems: usize,
    pub sems: Vec<Sem>,
    pub semid_ds: SemidDs,
    pub wait_queue: Arc<WaitQueue>,
    pub removed: bool,
}

impl SemSetInner {
    pub fn new(key: i32, semid: i32, nsems: usize, mode: u16, pid: i32) -> Self {
        let mut sems = Vec::with_capacity(nsems);
        for _ in 0..nsems {
            sems.push(Sem {
                semval: 0,
                sempid: pid,
                semncnt: 0,
                semzcnt: 0,
            });
        }
        Self {
            semid,
            nsems,
            sems,
            semid_ds: SemidDs::new(key, nsems, mode, pid),
            wait_queue: Arc::new(WaitQueue::new()),
            removed: false,
        }
    }
}

#[derive(Clone, Copy, Debug)]
pub struct SemUndoEntry {
    pub semid: i32,
    pub sem_num: u16,
