}

struct BiBTreeMap<K: Ord, V: Ord> {
    forward: BTreeMap<K, V>,
    reverse: BTreeMap<V, K>,
}

impl<K: Ord + Clone, V: Ord + Clone> BiBTreeMap<K, V> {
    const fn new() -> Self {
        Self {
            forward: BTreeMap::new(),
            reverse: BTreeMap::new(),
        }
    }

    fn insert(&mut self, key: K, value: V) {
        self.forward.insert(key.clone(), value.clone());
        self.reverse.insert(value, key);
    }

    fn get_by_key(&self, key: &K) -> Option<&V> {
        self.forward.get(key)
    }

    fn remove_by_value(&mut self, value: &V) {
        if let Some(key) = self.reverse.remove(value) {
            self.forward.remove(&key);
        }
    }
}

pub struct SemManager {
    key_semid: BiBTreeMap<i32, i32>,
    semid_inner: BTreeMap<i32, Arc<Mutex<SemSetInner>>>,
    next_semid: AtomicI32,
}

impl SemManager {
    const fn new() -> Self {
        Self {
            key_semid: BiBTreeMap::new(),
            semid_inner: BTreeMap::new(),
            next_semid: AtomicI32::new(1),
        }
    }

    fn next_id(&self) -> i32 {
        self.next_semid.fetch_add(1, Ordering::Relaxed)
    }

    pub fn get_semid_by_key(&self, key: i32) -> Option<i32> {
        self.key_semid.get_by_key(&key).copied()
    }

    pub fn get_inner_by_semid(&self, semid: i32) -> Option<Arc<Mutex<SemSetInner>>> {
        self.semid_inner.get(&semid).cloned()
    }

    pub fn insert_key_semid(&mut self, key: i32, semid: i32) {
        self.key_semid.insert(key, semid);
    }

    pub fn insert_semid_inner(&mut self, semid: i32, sem_inner: Arc<Mutex<SemSetInner>>) {
        self.semid_inner.insert(semid, sem_inner);
    }

    pub fn remove_semid(&mut self, semid: i32) {
        self.key_semid.remove_by_value(&semid);
        self.semid_inner.remove(&semid);
    }

    pub fn create_sem(&mut self, key: i32, nsems: usize, semflg: i32, pid: i32) -> AxResult<i32> {
        let mode = (semflg & 0o777) as u16;

        if key != IPC_PRIVATE {
            if let Some(semid) = self.get_semid_by_key(key) {
                if (semflg & IPC_EXCL) != 0 {
                    return ax_err!(AlreadyExists, "semget: key already exists with IPC_EXCL");
                }
                let inner = self
                    .get_inner_by_semid(semid)
                    .ok_or(AxError::InvalidInput)?;
                let inner = inner.lock();
                if nsems > inner.nsems {
                    return ax_err!(InvalidInput, "semget: nsems greater than existing set");
                }
                return Ok(semid);
            }
        }

        if nsems == 0 {
            return ax_err!(InvalidInput, "semget: nsems must be > 0 when creating a new set");
        }

        let semid = self.next_id();
        let inner = SemSetInner::new(key, semid, nsems, mode, pid);
        let inner = Arc::new(Mutex::new(inner));
        if key != IPC_PRIVATE {
            self.insert_key_semid(key, semid);
        }
        self.insert_semid_inner(semid, inner);
        Ok(semid)
    }
}

pub static SEM_MANAGER: Lazy<Mutex<SemManager>> = Lazy::new(|| Mutex::new(SemManager::new()));

pub fn exit_sem_undos(pid: i32, undos: Vec<SemUndoEntry>) {
    let manager = SEM_MANAGER.lock();
    for entry in undos {
        if let Some(semset_arc) = manager.get_inner_by_semid(entry.semid) {
            let mut semset = semset_arc.lock();
            let idx = entry.sem_num as usize;
            if idx < semset.sems.len() {
                let sem = &mut semset.sems[idx];
                sem.semval = (sem.semval as i16).saturating_add(entry.undo_val) as u16;
                sem.sempid = pid;
            }
            semset.wait_queue.notify_all(true);
        }
    }
}

use alloc::collections::BTreeMap;
use alloc::sync::Arc;
use spin::{Lazy, Mutex};
use axerrno::{LinuxError, LinuxResult};
use crate::fd_table::FdObject;

pub const LOCK_SH: i32 = 1;
pub const LOCK_EX: i32 = 2;
pub const LOCK_NB: i32 = 4;
pub const LOCK_UN: i32 = 8;

#[derive(Clone, Copy, Debug, PartialEq, Eq, PartialOrd, Ord)]
pub enum LockTarget {
    Location { fs_id: usize, inode: u64 },
    FdObject(usize),
}

pub fn get_lock_target(obj: &Arc<dyn FdObject>) -> LockTarget {
    if let Some(loc) = obj.location() {
        let fs_id = loc.filesystem() as *const dyn axfs_ng_vfs::FilesystemOps as *const () as usize;
        LockTarget::Location {
            fs_id,
            inode: loc.inode(),
        }
    } else {
        LockTarget::FdObject(Arc::as_ptr(obj) as *const () as usize)
    }
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum FlockType {
    Shared,
    Exclusive,
}

struct LockState {
    lock_type: FlockType,
    owners: alloc::vec::Vec<usize>,
    wait_queue: Arc<axtask::WaitQueue>,
}

static FLOCK_MAP: Lazy<Mutex<BTreeMap<LockTarget, LockState>>> =
    Lazy::new(|| Mutex::new(BTreeMap::new()));

fn current_has_pending_signal() -> bool {
    crate::task::current_thread()
        .map(|thread| thread.has_pending_signal())
        .unwrap_or(false)
}

pub fn do_flock(owner: usize, target: LockTarget, operation: i32) -> LinuxResult<isize> {
    let is_sh = (operation & LOCK_SH) != 0;
    let is_ex = (operation & LOCK_EX) != 0;
    let is_un = (operation & LOCK_UN) != 0;
    let is_nb = (operation & LOCK_NB) != 0;

    let mode_count = (is_sh as i32) + (is_ex as i32) + (is_un as i32);
    if mode_count != 1 {
        return Err(LinuxError::EINVAL);
    }

    let allowed_flags = LOCK_SH | LOCK_EX | LOCK_NB | LOCK_UN;
    if (operation & !allowed_flags) != 0 {
        return Err(LinuxError::EINVAL);
    }

    if is_un {
        flock_release_target_owner(owner, target);
        return Ok(0);
    }

    let lock_type = if is_sh {
        FlockType::Shared
    } else {
        FlockType::Exclusive
    };

    // First check if we need to convert/release an existing lock of a different type
    {
        let mut map = FLOCK_MAP.lock();
        if let Some(state) = map.get_mut(&target) {
            if state.owners.contains(&owner) {
                if state.lock_type == lock_type {
                    // Already have the same lock type, nothing to do
                    return Ok(0);
                }
                // Different lock type: release old lock first to prevent deadlocks during conversion
                let pos = state.owners.iter().position(|&x| x == owner).unwrap();
                state.owners.remove(pos);
                if state.owners.is_empty() {
                    let wq = state.wait_queue.clone();
                    map.remove(&target);
                    wq.notify_all(true);
                } else {
                    state.wait_queue.notify_all(true);
                }
            }
        }
    }

    loop {
        let mut map = FLOCK_MAP.lock();
        if let Some(state) = map.get_mut(&target) {
            let holds_already = state.owners.contains(&owner);
            let can_acquire = match lock_type {
                FlockType::Shared => match state.lock_type {
                    FlockType::Shared => true,
                    FlockType::Exclusive => state.owners.len() == 1 && holds_already,
                },
                FlockType::Exclusive => {
                    if holds_already {
                        state.owners.len() == 1
                    } else {
                        state.owners.is_empty()
                    }
                }
            };

            if can_acquire {
                state.lock_type = lock_type;
                if !holds_already {
                    state.owners.push(owner);
                }
                return Ok(0);
            }

            if is_nb {
                return Err(LinuxError::EAGAIN);
            }

            let wq = state.wait_queue.clone();
            drop(map);

            if current_has_pending_signal() {
                return Err(LinuxError::EINTR);
            }

            wq.wait_until(|| {
                let map = FLOCK_MAP.lock();
                if let Some(state) = map.get(&target) {
                    let holds_already = state.owners.contains(&owner);
                    let can_acquire = match lock_type {
                        FlockType::Shared => match state.lock_type {
                            FlockType::Shared => true,
                            FlockType::Exclusive => state.owners.len() == 1 && holds_already,
                        },
                        FlockType::Exclusive => {
                            if holds_already {
                                state.owners.len() == 1
                            } else {
                                state.owners.is_empty()
                            }
                        }
                    };
                    can_acquire || current_has_pending_signal()
                } else {
                    true
                }
            });

            if current_has_pending_signal() {
                return Err(LinuxError::EINTR);
            }
        } else {
            let state = LockState {
                lock_type,
                owners: alloc::vec![owner],
                wait_queue: Arc::new(axtask::WaitQueue::new()),
            };
            map.insert(target, state);
            return Ok(0);
        }
    }
}

pub fn flock_release_target_owner(owner: usize, target: LockTarget) {
    let mut map = FLOCK_MAP.lock();
    if let Some(state) = map.get_mut(&target) {
        if let Some(pos) = state.owners.iter().position(|&x| x == owner) {
            state.owners.remove(pos);
            if state.owners.is_empty() {
                let wq = state.wait_queue.clone();
                map.remove(&target);
                wq.notify_all(true);
            } else {
                state.wait_queue.notify_all(true);
            }
        }
    }
}

pub fn flock_release_owner(owner: usize) {
    let mut map = FLOCK_MAP.lock();
    let mut to_remove = alloc::vec::Vec::new();
    for (target, state) in map.iter_mut() {
        if let Some(pos) = state.owners.iter().position(|&x| x == owner) {
            state.owners.remove(pos);
