}

pub fn sys_read(fd: usize, buf: usize, count: usize) -> isize {
    axlog::trace!("sys_read: fd={}, buf={:#x}, count={}", fd, buf, count);
    if buf == 0 && count != 0 {
        return -LinuxError::EFAULT.code() as isize;
    }
