}

pub fn get_loop_size(id: usize) -> Option<u64> {
    if id >= 8 {
        return None;
    }
    let dev = &fs::loop_dev::LOOP_DEVICES[id];
    if dev.backing.lock().is_some() {
        Some(dev.size.load(core::sync::atomic::Ordering::Acquire))
    } else {
