/// The base scheduler trait that all schedulers should implement.
///
/// All tasks in the scheduler are considered runnable. If a task is go to
/// sleep, it should be removed from the scheduler.
pub trait BaseScheduler {
    /// Type of scheduled entities. Often a task struct.
    type SchedItem;

    /// Initializes the scheduler.
    fn init(&mut self);

    /// Adds a task to the scheduler.
    fn add_task(&mut self, task: Self::SchedItem);

    /// Removes a task by its reference from the scheduler. Returns the owned
    /// removed task with ownership if it exists.
    ///
    /// # Safety
    ///
    /// The caller should ensure that the task is in the scheduler, otherwise
    /// the behavior is undefined.
    fn remove_task(&mut self, task: &Self::SchedItem) -> Option<Self::SchedItem>;

    /// Picks the next task to run, it will be removed from the scheduler.
    /// Returns [`None`] if there is not runnable task.
    fn pick_next_task(&mut self) -> Option<Self::SchedItem>;

    /// Puts the previous task back to the scheduler. The previous task is
    /// usually placed at the end of the ready queue, making it less likely
    /// to be re-scheduled.
    ///
    /// `preempt` indicates whether the previous task is preempted by the next
    /// task. In this case, the previous task may be placed at the front of the
    /// ready queue.
    fn put_prev_task(&mut self, prev: Self::SchedItem, preempt: bool);

    /// Advances the scheduler state at each timer tick. Returns `true` if
    /// re-scheduling is required.
    ///
    /// `current` is the current running task.
    fn task_tick(&mut self, current: &Self::SchedItem) -> bool;

    /// set priority for a task
    fn set_priority(&mut self, task: &Self::SchedItem, prio: isize) -> bool;

    /// Returns `true` if there are no tasks in the scheduler's ready queue.
    fn is_empty(&self) -> bool;
}

fn futex_key(&self, addr: usize, is_private: bool) -> (usize, bool) {
    if is_private {
        (addr, true)
    } else {
        let aspace_handle = self.aspace_handle();
        let aspace = aspace_handle.read();
        let vaddr = VirtAddr::from(addr);
        let query_res = aspace.query_vaddr(vaddr);
        let paddr = match query_res {
            Ok((paddr, ..)) => paddr.as_usize(),
            Err(_) => {
                // Try to handle page fault on-demand (simulate a read fault from user space to populate it)
                let mut paddr_res = addr;
                match aspace.handle_page_fault(
                    vaddr,
                    axhal::trap::PageFaultFlags::READ | axhal::trap::PageFaultFlags::USER,
                ) {
                    axmm::PageFaultResult::Handled(success) => {
                        if success {
                            if let Ok((paddr, ..)) = aspace.query_vaddr(vaddr) {
                                paddr_res = paddr.as_usize();
                            }
                        }
                    }
                    axmm::PageFaultResult::NeedWriteLock => {
                        drop(aspace);
                        let mut aspace_write = aspace_handle.write();
                        if aspace_write.handle_page_fault_write(
                            vaddr,
                            axhal::trap::PageFaultFlags::READ
                                | axhal::trap::PageFaultFlags::USER,
                        ) {
                            if let Ok((paddr, ..)) = aspace_write.query_vaddr(vaddr) {
                                paddr_res = paddr.as_usize();
                            }
                        }
                    }
                }
                paddr_res
            }
        };
        axlog::debug!("futex_key: addr={:#x}, paddr={:#x}", addr, paddr);
        (paddr, false)
    }
}

pub fn futex_waitv(
    &self,
    waiters_addr: usize,
    nr_futexes: u32,
    _flags: u32,
    timeout_ns: Option<u64>,
) -> AxResult<isize> {
    let mut waiters = alloc::vec::Vec::with_capacity(nr_futexes as usize);
    for i in 0..nr_futexes {
        let mut w = FutexWaitv::default();
        let buf = unsafe {
            core::slice::from_raw_parts_mut(
                &mut w as *mut _ as *mut u8,
                core::mem::size_of::<FutexWaitv>(),
            )
        };
        self.read_user_bytes(
            waiters_addr + i as usize * core::mem::size_of::<FutexWaitv>(),
            buf,
        )?;
        waiters.push(w);
    }

    for w in &waiters {
        if w.__reserved != 0 {
            return Err(AxError::InvalidInput);
        }
        let valid_flags = 0x02 | 0x80;
        if (w.flags & !valid_flags) != 0 || (w.flags & 0x03) != 0x02 {
            return Err(AxError::InvalidInput);
        }
        if w.uaddr % 4 != 0 {
            return Err(AxError::InvalidInput);
        }
        if w.uaddr == 0 {
            return Err(AxError::BadAddress);
        }
        let val = self.read_user_u32(w.uaddr as usize)?;
        if val != w.val as u32 {
            return Err(AxError::from(AxErrorKind::WouldBlock));
        }
        self.write_user_bytes(w.uaddr as usize, &val.to_ne_bytes())?;
    }

    // Translate the virtual addresses to physical addresses outside the run queue lock.
    let mut kvaddrs = alloc::vec::Vec::with_capacity(waiters.len());
    let aspace = self.aspace_handle();
    let aspace_guard = aspace.read();
    for w in &waiters {
        let start = VirtAddr::from(w.uaddr as usize);
        let (paddr, ..) = aspace_guard
            .query_vaddr(start)
            .map_err(|_| AxError::BadAddress)?;
        let paddr = paddr.align_down_4k() + start.align_offset_4k();
        let kvaddr = axhal::mem::phys_to_virt(paddr);
        kvaddrs.push(kvaddr.as_usize());
    }
    drop(aspace_guard);

    let current_thread = super::current_thread().ok();
    let signal_pending = || {
        current_thread
            .as_ref()
            .map(|thread| thread.has_pending_signal())
            .unwrap_or(false)
    };

    if signal_pending() {
        return Err(unsafe { core::mem::transmute(-512i32) }); // ERESTARTSYS
    }

    let mut queues = alloc::vec::Vec::with_capacity(waiters.len());
    for w in &waiters {
        let is_priv = w.flags & 128 != 0; // 128 is FUTEX_PRIVATE_FLAG
        let (key, is_priv) = self.futex_key(w.uaddr as usize, is_priv);
        let queue = if is_priv {
            self.futex_table.queue(key)
        } else {
            GLOBAL_FUTEX_TABLE.queue(key)
        };
        queues.push(queue);
    }

    let q_refs: alloc::vec::Vec<&axtask::WaitQueue> =
        queues.iter().map(|q| q.as_ref()).collect();

    let first_time = core::cell::Cell::new(true);
    let mut mismatch = false;

    let res = axtask::WaitQueue::wait_multiple_timeout_until(
        &q_refs,
        timeout_ns.map(core::time::Duration::from_nanos),
        || {
            if first_time.get() {
                first_time.set(false);
                if self.group_exiting() || signal_pending() {
                    return true;
                }
                mismatch = false;
                for (i, w) in waiters.iter().enumerate() {
                    let kvaddr = kvaddrs[i];
                    let val = unsafe { core::ptr::read_volatile(kvaddr as *const u32) };
                    if val != w.val as u32 {
                        mismatch = true;
                        return true;
                    }
                }
                false
            } else {
                true
            }
        },
    );

    // Remove from GLOBAL_FUTEX_TABLE if empty
    if self.group_exiting() || mismatch || res.is_ok() || res.is_err() {
        for (_i, w) in waiters.iter().enumerate() {
            let is_priv = w.flags & 128 != 0;
            if !is_priv {
                let (key, _) = self.futex_key(w.uaddr as usize, is_priv);
                GLOBAL_FUTEX_TABLE.remove_if_empty(key);
            }
        }
    }

    if mismatch {
        return Err(AxError::from(AxErrorKind::WouldBlock)); // EAGAIN
    }

    if signal_pending() {
        return Err(unsafe { core::mem::transmute(-512i32) }); // ERESTARTSYS
    }

    match res {
        Ok(idx) => Ok(idx as isize),
        Err(true) => Err(AxError::from(AxErrorKind::TimedOut)),
        Err(false) => Err(unsafe { core::mem::transmute(-512i32) }), // Aborted not by timeout
    }
}

