use alloc::vec::Vec;

use axerrno::{AxError, AxResult};

use super::Process;

pub const DEFAULT_USER_CSTRING_MAX: usize = 4096;

pub fn read_user_cstring_bytes(
    process: &Process,
    user_addr: usize,
    max_len: usize,
) -> AxResult<(Vec<u8>, bool)> {
    let mut bytes = Vec::new();
    if bytes.try_reserve_exact(max_len).is_err() {
        return Err(AxError::NoMemory);
    }
    for i in 0..max_len {
        let mut byte = [0u8; 1];
        process.read_user_bytes(user_addr + i, &mut byte)?;
        if byte[0] == 0 {
            return Ok((bytes, true));
        }
        bytes.push(byte[0]);
    }
    Ok((bytes, false))
}

pub fn read_user_plain<T: Copy>(process: &Process, user_addr: usize) -> AxResult<T> {
    let mut value = core::mem::MaybeUninit::<T>::uninit();
    let bytes = unsafe {
        core::slice::from_raw_parts_mut(value.as_mut_ptr().cast::<u8>(), core::mem::size_of::<T>())
    };
    process.read_user_bytes(user_addr, bytes)?;
    Ok(unsafe { value.assume_init() })
}

pub fn write_user_plain<T: Copy>(process: &Process, user_addr: usize, value: &T) -> AxResult<()> {
    let bytes = unsafe {
        core::slice::from_raw_parts((value as *const T).cast::<u8>(), core::mem::size_of::<T>())
    };
    process.write_user_bytes(user_addr, bytes)
}

pub fn write_user_bytes(process: &Process, user_addr: usize, bytes: &[u8]) -> AxResult<()> {
    process.write_user_bytes(user_addr, bytes)
}

pub fn read_user_plain_array<T: Copy>(
    process: &Process,
    user_addr: usize,
    count: usize,
) -> AxResult<Vec<T>> {
    let mut out = Vec::new();
    if out.try_reserve_exact(count).is_err() {
        return Err(AxError::NoMemory);
    }
    let elem_size = core::mem::size_of::<T>();
    for i in 0..count {
        let byte_off = i.checked_mul(elem_size).ok_or(AxError::InvalidInput)?;
        let addr = user_addr
            .checked_add(byte_off)
            .ok_or(AxError::InvalidInput)?;
        out.push(read_user_plain(process, addr)?);
    }
    Ok(out)
}

pub fn write_user_plain_array<T: Copy>(
    process: &Process,
    user_addr: usize,
    values: &[T],
) -> AxResult<()> {
    let elem_size = core::mem::size_of::<T>();
    for (i, val) in values.iter().enumerate() {
        let byte_off = i.checked_mul(elem_size).ok_or(AxError::InvalidInput)?;
        let addr = user_addr
            .checked_add(byte_off)
            .ok_or(AxError::InvalidInput)?;
        write_user_plain(process, addr, val)?;
    }
    Ok(())
}

use alloc::{collections::BTreeMap, sync::Arc};
use core::sync::atomic::{AtomicI32, Ordering};

use spin::{Lazy, Mutex};

const UNCONSTRAINED_LATENCY_US: i32 = i32::MAX;

#[derive(Default)]
struct CpuDmaLatencyState {
    next_id: u64,
    requests: BTreeMap<u64, i32>,
}

impl CpuDmaLatencyState {
    fn effective_value(&self) -> i32 {
        self.requests
            .values()
            .copied()
            .min()
            .unwrap_or(UNCONSTRAINED_LATENCY_US)
    }
}

static CPU_DMA_LATENCY_STATE: Lazy<Mutex<CpuDmaLatencyState>> =
    Lazy::new(|| Mutex::new(CpuDmaLatencyState::default()));
static CPU_DMA_LATENCY_EFFECTIVE: AtomicI32 = AtomicI32::new(UNCONSTRAINED_LATENCY_US);

fn apply_effective_latency(value: i32) {
    CPU_DMA_LATENCY_EFFECTIVE.store(value, Ordering::Release);
}

pub fn effective_latency_us() -> i32 {
    CPU_DMA_LATENCY_EFFECTIVE.load(Ordering::Acquire)
}

pub struct CpuDmaLatencyRequest {
    id: u64,
}

impl CpuDmaLatencyRequest {
    pub fn new() -> Arc<Self> {
        let (id, effective) = {
            let mut state = CPU_DMA_LATENCY_STATE.lock();
            let id = state.next_id;
            state.next_id = state.next_id.wrapping_add(1);
            state.requests.insert(id, UNCONSTRAINED_LATENCY_US);
            (id, state.effective_value())
        };
        apply_effective_latency(effective);
        Arc::new(Self { id })
    }

    pub fn set_target_us(&self, value: i32) {
        let effective = {
            let mut state = CPU_DMA_LATENCY_STATE.lock();
            if let Some(slot) = state.requests.get_mut(&self.id) {
                *slot = value;
            } else {
                return;
            }
            state.effective_value()
        };
        apply_effective_latency(effective);
    }
}

impl Drop for CpuDmaLatencyRequest {
    fn drop(&mut self) {
        let effective = {
            let mut state = CPU_DMA_LATENCY_STATE.lock();
            state.requests.remove(&self.id);
            state.effective_value()
        };
        apply_effective_latency(effective);
    }
}

